import random
from solution import LRUCache, LFUCache

class BruteLRU:
    def __init__(s,c): s.c=c;s.d={};s.o=[]
    def get(s,k):
        if k not in s.d: return -1
        s.o.remove(k);s.o.append(k);return s.d[k]
    def put(s,k,v):
        if k in s.d: s.d[k]=v;s.o.remove(k);s.o.append(k);return
        if len(s.d)>=s.c: del s.d[s.o.pop(0)]
        s.d[k]=v;s.o.append(k)

class BruteLFU:
    def __init__(s,c): s.c=c;s.d={};s.f={};s.t={};s.clk=0
    def get(s,k):
        if k not in s.d: return -1
        s.f[k]+=1;s.clk+=1;s.t[k]=s.clk;return s.d[k]
    def put(s,k,v):
        if s.c==0: return
        if k in s.d: s.d[k]=v;s.f[k]+=1;s.clk+=1;s.t[k]=s.clk;return
        if len(s.d)>=s.c:
            victim=min(s.d,key=lambda x:(s.f[x],s.t[x]))
            del s.d[victim];del s.f[victim];del s.t[victim]
        s.clk+=1;s.d[k]=v;s.f[k]=1;s.t[k]=s.clk

okL=okF=True
for seed in range(5000):
    random.seed(seed); cap=random.randint(1,5)
    a,b=LRUCache(cap),BruteLRU(cap)
    c,d=LFUCache(cap),BruteLFU(cap)
    for _ in range(50):
        op=random.random(); k=random.randint(0,6)
        if op<0.5:
            if a.get(k)!=b.get(k): okL=False
            if c.get(k)!=d.get(k): okF=False
        else:
            v=random.randint(0,100); a.put(k,v);b.put(k,v);c.put(k,v);d.put(k,v)
print("LRU 5000 seeds match:",okL)
print("LFU 5000 seeds match:",okF)

